import{c as n,Q as s,j as e,m as t}from"./chunks/framework.BVCVcpew.js";const b=JSON.parse('{"title":"功能特性","description":"","frontmatter":{},"headers":[],"relativePath":"zh/features.md","filePath":"zh/features.md"}'),r={name:"zh/features.md"};function l(i,a,o,d,p,c){return s(),e("div",null,[...a[0]||(a[0]=[t(`<h1 id="功能特性" tabindex="-1">功能特性 <a class="header-anchor" href="#功能特性" aria-label="Permalink to &quot;功能特性&quot;">​</a></h1><h2 id="核心架构" tabindex="-1">核心架构 <a class="header-anchor" href="#核心架构" aria-label="Permalink to &quot;核心架构&quot;">​</a></h2><p>GlobalPulse 基于 <strong>Cloudflare Workers</strong> 构建，采用模块化架构：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│                    Cloudflare Worker                        │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│  管理后台  │  调度器  │  研究引擎  │  推送服务              │</span></span>
<span class="line"><span>│    (HTML)  │  (Cron)  │  (LLM+数据)│  (Providers)          │</span></span>
<span class="line"><span>├─────────────────────────────────────────────────────────────┤</span></span>
<span class="line"><span>│              KV 命名空间  │  D1 数据库                     │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="管理后台" tabindex="-1">管理后台 <a class="header-anchor" href="#管理后台" aria-label="Permalink to &quot;管理后台&quot;">​</a></h2><p>密码保护配置界面，访问 <code>/admin</code>：</p><ul><li><strong>全局设置</strong>：应用名、语言、时区、输出格式</li><li><strong>任务构建器</strong>：可视化定时调度，支持批量创建</li><li><strong>渠道配置</strong>：飞书、微信、Telegram、Email 设置</li><li><strong>实时预览</strong>：查看每个渠道将收到的消息格式</li><li><strong>推送日志</strong>：追踪发送记录和时间戳</li></ul><h2 id="定时简报" tabindex="-1">定时简报 <a class="header-anchor" href="#定时简报" aria-label="Permalink to &quot;定时简报&quot;">​</a></h2><table tabindex="0"><thead><tr><th>功能</th><th>描述</th></tr></thead><tbody><tr><td><strong>执行间隔</strong></td><td>通过 Cloudflare Cron 每5分钟执行</td></tr><tr><td><strong>时区支持</strong></td><td>完整 IANA 时区数据库</td></tr><tr><td><strong>交易日</strong></td><td>美股、A股、加密货币日历</td></tr><tr><td><strong>市场时段</strong></td><td>盘前、盘中、盘后</td></tr><tr><td><strong>多任务</strong></td><td>最多20个独立任务</td></tr></tbody></table><h2 id="市场情报" tabindex="-1">市场情报 <a class="header-anchor" href="#市场情报" aria-label="Permalink to &quot;市场情报&quot;">​</a></h2><h3 id="支持的市场" tabindex="-1">支持的市场 <a class="header-anchor" href="#支持的市场" aria-label="Permalink to &quot;支持的市场&quot;">​</a></h3><table tabindex="0"><thead><tr><th>市场</th><th>数据源</th></tr></thead><tbody><tr><td><strong>美股</strong></td><td>Yahoo Finance, Stooq, Twelve Data, Finnhub, Alpha Vantage</td></tr><tr><td><strong>A股</strong></td><td>东方财富, 新浪, 腾讯, Twelve Data</td></tr><tr><td><strong>加密货币</strong></td><td>Binance, CoinGecko, Alternative.me</td></tr></tbody></table><h3 id="报告模块" tabindex="-1">报告模块 <a class="header-anchor" href="#报告模块" aria-label="Permalink to &quot;报告模块&quot;">​</a></h3><p>每个任务可独立开关：</p><ul><li><code>us_market</code> - 美股ETF行情和涨跌幅</li><li><code>a_share</code> - A股指数行情</li><li><code>crypto</code> - 加密货币现货价格</li><li><code>fear_greed</code> - 恐慌贪婪指数</li><li><code>technicals</code> - RSI/MA 技术信号</li><li><code>sentiment</code> - 新闻情绪评分</li><li><code>news</code> - 新闻摘要</li><li><code>catalysts</code> - 政策/事件催化剂</li><li><code>x_sentiment</code> - Twitter 情绪</li><li><code>positions</code> - 持仓数据</li><li><code>macro</code> - 宏观背景（美联储、CPI、财报）</li></ul><h2 id="ai-研究引擎" tabindex="-1">AI 研究引擎 <a class="header-anchor" href="#ai-研究引擎" aria-label="Permalink to &quot;AI 研究引擎&quot;">​</a></h2><p>两种报告模式：</p><h3 id="摘要模式-digest" tabindex="-1">摘要模式 (Digest) <a class="header-anchor" href="#摘要模式-digest" aria-label="Permalink to &quot;摘要模式 (Digest)&quot;">​</a></h3><p>简单的主题聚合，来自 RSS 和新闻源。</p><h3 id="市场模式-market" tabindex="-1">市场模式 (Market) <a class="header-anchor" href="#市场模式-market" aria-label="Permalink to &quot;市场模式 (Market)&quot;">​</a></h3><p>完整研究引擎：</p><ol><li>多源数据获取 + 降级链路</li><li>宏观数据收集（美联储、CPI、财报）</li><li>新闻证据构建</li><li>LLM 分析（Gemini → Workers AI → 确定性降级）</li><li>带置信度的股票卡片</li><li>D1 持久化历史</li></ol><h2 id="推送渠道" tabindex="-1">推送渠道 <a class="header-anchor" href="#推送渠道" aria-label="Permalink to &quot;推送渠道&quot;">​</a></h2><table tabindex="0"><thead><tr><th>渠道</th><th>特性</th></tr></thead><tbody><tr><td><strong>飞书</strong></td><td>Webhook + HMAC 签名</td></tr><tr><td><strong>微信公众号</strong></td><td>App ID/Secret + OpenID</td></tr><tr><td><strong>微信 clawbot</strong></td><td>Webhook 推送</td></tr><tr><td><strong>Telegram</strong></td><td>HTML 格式化，内联键盘</td></tr><tr><td><strong>Email</strong></td><td>Brevo/Resend，HTML 模板</td></tr></tbody></table><h2 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h2><ul><li>管理后台密码保护（cookie 或 header 认证）</li><li>API Token 认证接口</li><li>KV 配置存储（代码中不存 secrets）</li><li>飞书 Webhook HMAC 签名验证</li></ul><h2 id="api-接口" tabindex="-1">API 接口 <a class="header-anchor" href="#api-接口" aria-label="Permalink to &quot;API 接口&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET  /              → 重定向到 /admin</span></span>
<span class="line"><span>GET  /admin         → 管理后台</span></span>
<span class="line"><span>GET  /health        → 健康检查</span></span>
<span class="line"><span>POST /v1/messages   → 发送消息</span></span>
<span class="line"><span>POST /v1/events/github-actions</span></span>
<span class="line"><span>POST /v1/events/cloudflare</span></span>
<span class="line"><span>GET  /api/admin/settings</span></span>
<span class="line"><span>PUT  /api/admin/settings</span></span>
<span class="line"><span>POST /api/admin/preview</span></span>
<span class="line"><span>POST /api/admin/run</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div>`,28)])])}const u=n(r,[["render",l]]);export{b as __pageData,u as default};
